#: Mapping of supported priority names to Unix ``nice`` increments.
_PROCESS_PRIORITY_NICE = {
    "low": 10,
    "below_normal": 5,
    "normal": 0,
    "above_normal": -5,
    "high": -10,
}

#: Mapping of supported priority names to Windows priority classes.
_PROCESS_PRIORITY_WIN = {
    "low": 0x00000040,  # IDLE_PRIORITY_CLASS
    "below_normal": 0x00004000,  # BELOW_NORMAL_PRIORITY_CLASS
    "normal": 0x00000020,  # NORMAL_PRIORITY_CLASS
    "above_normal": 0x00008000,  # ABOVE_NORMAL_PRIORITY_CLASS
    "high": 0x00000080,  # HIGH_PRIORITY_CLASS
}


class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension

        if process_priority is not None and process_priority not in (
            _PROCESS_PRIORITY_NICE
        ):
            process_priority = None

        self.process_priority = process_priority

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _set_process_priority(self, pid: int) -> None:
        """Best-effort attempt to set the priority of the editor
        process.  Any failure is silently ignored since the editor
        should still work with the default priority.
        """
        if self.process_priority is None:
            return

        try:
            if WIN:
                import ctypes

                priority_class = _PROCESS_PRIORITY_WIN[self.process_priority]
                handle = ctypes.windll.kernel32.OpenProcess(  # type: ignore[attr-defined]
                    0x0200 | 0x0400, False, pid  # PROCESS_SET_INFORMATION | QUERY
                )
                if handle:
                    try:
                        ctypes.windll.kernel32.SetPriorityClass(  # type: ignore[attr-defined]
                            handle, priority_class
                        )
                    finally:
                        ctypes.windll.kernel32.CloseHandle(handle)  # type: ignore[attr-defined]
            else:
                niceness = _PROCESS_PRIORITY_NICE[self.process_priority]
                os.setpriority(os.PRIO_PROCESS, pid, niceness)
        except Exception:
            # Setting the priority is a best-effort operation. If it's
            # not supported on this platform, or the process doesn't
            # have permission to change it, just ignore the failure.
            pass

