def _popen_priority_kwargs(self) -> dict[str, t.Any]:
    """Best-effort, platform specific ``Popen`` keyword arguments
    used to launch the editor with the requested process
    priority.  Returns an empty ``dict`` if no priority was
    requested or the current platform has no known mechanism for
    it, so the editor always launches with default priority as a
    fallback.
    """
    if self.process_priority is None:
        return {}

    if WIN:
        return {"creationflags": _PROCESS_PRIORITY_WIN[self.process_priority]}

    niceness = _PROCESS_PRIORITY_NICE[self.process_priority]

    def preexec_fn() -> None:
        try:
            os.nice(niceness)
        except OSError:
            # Not permitted (e.g. raising priority without
            # privileges) or unsupported. Fall back to the
            # default priority rather than aborting the edit.
            pass

    return {"preexec_fn": preexec_fn}

